options.styles:
.status-header {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 16px;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  background: #1E223C;
  color: white;
  border-radius: 20px;
  padding: 10px 24px;
  box-shadow: 0px 4px 6px rgba(0, 0, 0, 0.3);
  flex-wrap: wrap;
}

.status-icons {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  flex-shrink: 0;
  flex-wrap: wrap;
}

.status-icon {
  height: 60px;
  width: auto;
  display: block;
  max-width: 100%;
}

/* Logo MikroTik em branco */
.status-icon.mikrotik {
  height: 52px;
  width: auto;
  filter: brightness(0) invert(1);
}

.status-icon.vmware {
  height: 42px;
}

.status-icon.veeam {
  height: 34px;
}

.status-title {
  flex: 1 1 320px;
  min-width: 0;
  text-align: center;
  font-size: 35px;
  font-weight: bold;
  line-height: 1.2;
  white-space: normal;
  word-break: break-word;
  overflow-wrap: anywhere;
}

@media (max-width: 1100px) {
  .status-header {
    padding: 10px 18px;
    gap: 12px;
  }

  .status-title {
    font-size: 28px;
    text-align: center;
  }

  .status-icon {
    height: 52px;
  }

  .status-icon.mikrotik {
    height: 46px;
    filter: brightness(0) invert(1);
  }

  .status-icon.vmware {
    height: 38px;
  }

  .status-icon.veeam {
    height: 30px;
  }
}

@media (max-width: 768px) {
  .status-header {
    flex-direction: column;
    border-radius: 16px;
    padding: 12px 14px;
    gap: 10px;
    justify-content: center;
  }

  .status-icons {
    width: 100%;
    margin: 0;
    justify-content: center;
  }

  .status-icon {
    height: 42px;
  }

  .status-icon.mikrotik {
    height: 38px;
    filter: brightness(0) invert(1);
  }

  .status-icon.vmware {
    height: 30px;
  }

  .status-icon.veeam {
    height: 24px;
  }

  .status-title {
    width: 100%;
    flex: 0 1 auto;
    min-width: 0;
    font-size: 22px;
    line-height: 1.25;
    text-align: center;
    white-space: normal;
    word-break: break-word;
    overflow-wrap: anywhere;
  }
}

@media (max-width: 480px) {
  .status-header {
    padding: 10px 12px;
    border-radius: 14px;
    gap: 8px;
  }

  .status-icons {
    width: 100%;
    justify-content: center;
    gap: 8px;
  }

  .status-icon {
    height: 34px;
  }

  .status-icon.mikrotik {
    height: 32px;
    filter: brightness(0) invert(1);
  }

  .status-icon.vmware {
    height: 24px;
  }

  .status-icon.veeam {
    height: 20px;
  }

  .status-title {
    width: 100%;
    font-size: 18px;
    line-height: 1.3;
    text-align: center;
  }
}

