options.helpers:
context.handlebars.registerHelper('memoryColor', function (usage) {
  const value = parseFloat(usage.toString().replace('%', ''));
  if (value > 90) return '#e74c3c';
  if (value > 80) return '#ffcc00';
  return '#2ecc71';
});

