function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

const valueEl =
  context?.element?.querySelector?.("#cores-value") ||
  document.getElementById("cores-value");

const frames = context?.panelData?.series || [];
const cores = new Set();

for (const frame of frames) {
  const frameName = String(frame.name || "");

  for (const field of frame.fields || []) {
    const fieldName = String(field.name || "");
    const displayName = String(field.config?.displayName || "");
    const fullName = `${frameName} ${fieldName} ${displayName}`;

    let match = fullName.match(/#\s*([0-9]+)\s*:\s*CPU utilization/i);

    if (match) {
      cores.add(match[1]);
    }

    if (/field|name/i.test(fieldName)) {
      const names = valuesToArray(field.values);

      for (const name of names) {
        const text = String(name || "");
        match = text.match(/#\s*([0-9]+)\s*:\s*CPU utilization/i);

        if (match) {
          cores.add(match[1]);
        }
      }
    }
  }
}

if (valueEl) {
  valueEl.innerText = cores.size > 0 ? cores.size : "--";
}

