options.helpers:
const ports = ["ether1", "ether2", "ether3", "ether4", "ether5"];

const portInfo = {
  ether1: {
    label: "ether1",
    name: "LINK_VIVO",
    type: "WAN / Link dedicado",
    detail: "Status físico da porta VIVO"
  },
  ether2: {
    label: "ether2",
    name: "LINK_WEBCENTRO",
    type: "WAN / Banda larga",
    detail: "Status lógico pelo PPPoE Webcentro"
  },
  ether3: {
    label: "ether3",
    name: "AP",
    type: "Rede local",
    detail: "Conectado ao Access Point"
  },
  ether4: {
    label: "ether4",
    name: "DVR",
    type: "Rede local",
    detail: "Conectado ao DVR/NVR"
  },
  ether5: {
    label: "ether5",
    name: "SWITCH",
    type: "Rede local",
    detail: "Conectado ao switch da LAN"
  }
};

function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function getLastValue(field) {
  const values = valuesToArray(field.values);

  for (let i = values.length - 1; i >= 0; i--) {
    const v = values[i];

    if (v !== null && v !== undefined) {
      return v;
    }
  }

  return null;
}

function isUp(value) {
  const v = String(value ?? "").toLowerCase().trim();

  return (
    v === "1" ||
    v === "true" ||
    v === "up" ||
    v === "online" ||
    v === "running"
  );
}

function isDown(value) {
  const v = String(value ?? "").toLowerCase().trim();

  return (
    v === "0" ||
    v === "2" ||
    v === "false" ||
    v === "down" ||
    v === "offline"
  );
}

const statusByPort = {};
const logicalLinks = {};
const frames = context?.panelData?.series || [];

for (const frame of frames) {
  const frameName = String(frame.name || "").toLowerCase();

  for (const field of frame.fields || []) {
    if (String(field.type).toLowerCase() === "time") {
      continue;
    }

    const fieldName = String(field.name || "").toLowerCase();
    const displayName = String(field.config?.displayName || "").toLowerCase();
    const fullName = `${frameName} ${fieldName} ${displayName}`;

    for (const port of ports) {
      if (fullName.includes(port)) {
        const value = getLastValue(field);

        if (value !== null && value !== undefined) {
          statusByPort[port] = value;
        }
      }
    }

    const values = valuesToArray(field.values);

    for (const value of values) {
      if (value === null || value === undefined) {
        continue;
      }

      String(value)
        .split(/\r?\n/)
        .map(l => l.trim())
        .filter(l => l.startsWith("LINK_") && l.includes("|"))
        .forEach(line => {
          const p = line.split("|");
          const name = p[0] || "";

          if (name === "LINK_VIVO") {
            logicalLinks.ether1 = {
              linkName: "LINK_VIVO",
              physicalUp: isUp(p[2]),
              routeUp: isUp(p[3]),
              detail: isUp(p[2])
                ? "Link físico VIVO ativo"
                : "Link físico VIVO inativo"
            };
          }

          if (name === "LINK_WEBCENTRO") {
            logicalLinks.ether2 = {
              linkName: "LINK_WEBCENTRO",
              physicalUp: isUp(p[2]),
              pppoeUp: isUp(p[3]),
              routeUp: isUp(p[4]),
              detail: isUp(p[3])
                ? "PPPoE Webcentro conectado"
                : "PPPoE Webcentro desconectado"
            };
          }
        });
    }
  }
}

const finalStatus = {};

for (const port of ports) {
  finalStatus[port] = "unknown";

  const physical = statusByPort[port];

  if (isUp(physical)) {
    finalStatus[port] = "up";
  } else if (isDown(physical)) {
    finalStatus[port] = "down";
  }
}

/*
  Regra final:
  ether1 VIVO      = status físico da porta
  ether2 WEBCENTRO = status lógico do PPPoE
  ether3-5 LAN     = status físico
*/
if (logicalLinks.ether1) {
  finalStatus.ether1 = logicalLinks.ether1.physicalUp ? "up" : "down";
}

if (logicalLinks.ether2) {
  finalStatus.ether2 = logicalLinks.ether2.pppoeUp ? "up" : "down";
}

let onlineCount = 0;

for (const port of ports) {
  const el =
    context?.element?.querySelector?.(`.mk-rj-port[data-port="${port}"]`) ||
    document.querySelector(`.mk-rj-port[data-port="${port}"]`);

  if (!el) {
    continue;
  }

  const tooltip = el.querySelector(".mk-port-tooltip");

  const info = portInfo[port] || {
    label: port,
    name: port,
    type: "-",
    detail: "-"
  };

  el.classList.remove("link-up", "link-down", "link-unknown", "activity");

  let statusText = "SEM DADO";
  let detailText = info.detail;

  if (port === "ether1" && logicalLinks.ether1) {
    detailText = logicalLinks.ether1.detail;
  }

  if (port === "ether2" && logicalLinks.ether2) {
    detailText = logicalLinks.ether2.detail;
  }

  if (finalStatus[port] === "up") {
    el.classList.add("link-up");
    statusText = "ONLINE";
    onlineCount++;
  } else if (finalStatus[port] === "down") {
    el.classList.add("link-down");
    statusText = "OFFLINE";
  } else {
    el.classList.add("link-unknown");
    statusText = "SEM DADO";
  }

  const statusClass =
    statusText === "ONLINE"
      ? "status-online"
      : statusText === "OFFLINE"
        ? "status-offline"
        : "status-unknown";

  el.removeAttribute("title");

  if (tooltip) {
    tooltip.innerHTML = `
      <strong>${info.label} · ${info.name}</strong>
      <span>${info.type}</span>
      <span>${detailText}</span>
      <em class="${statusClass}">Status: ${statusText}</em>
    `;
  }
}

const badge =
  context?.element?.querySelector?.("#mk-panel-badge") ||
  document.getElementById("mk-panel-badge");

if (badge) {
  badge.innerText = `${onlineCount}/${ports.length} PORTAS ONLINE`;

  if (onlineCount === ports.length) {
    badge.style.background = "#2ecc71";
    badge.style.color = "#000";
  } else if (onlineCount > 0) {
    badge.style.background = "#ffcc00";
    badge.style.color = "#000";
  } else {
    badge.style.background = "#e74c3c";
    badge.style.color = "#fff";
  }
}

if (window.mkPortBlinkTimer) {
  clearInterval(window.mkPortBlinkTimer);
}

window.mkPortBlinkTimer = setInterval(() => {
  for (const port of ports) {
    const el =
      context?.element?.querySelector?.(`.mk-rj-port[data-port="${port}"]`) ||
      document.querySelector(`.mk-rj-port[data-port="${port}"]`);

    if (!el || !el.classList.contains("link-up")) {
      continue;
    }

    el.classList.toggle("activity", Math.random() > 0.45);
  }
}, 260);

