  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function isTrue(value) {
  const v = String(value ?? "").toLowerCase().trim();
  return v === "true" || v === "1" || v === "up" || v === "online" || v === "running";
}

function formatMbps(bits) {
  return (Number(bits || 0) / 1000000).toFixed(2);
}

function percent(bits, capacityMbps) {
  const mbps = Number(bits || 0) / 1000000;
  return Math.max(0, Math.min(100, capacityMbps ? (mbps / capacityMbps) * 100 : 0));
}

function collectLines() {
  const frames = context?.panelData?.series || [];
  const lines = [];

  for (const frame of frames) {
    for (const field of frame.fields || []) {
      if (String(field.type).toLowerCase() === "time") continue;

      for (const value of valuesToArray(field.values)) {
        if (value === null || value === undefined) continue;

        String(value)
          .split(/\r?\n/)
          .map(l => l.trim())
          .filter(l => l.startsWith("LINK_") && l.includes("|"))
          .forEach(l => lines.push(l));
      }
    }
  }

  return lines;
}

function parseLinks() {
  const links = {
    vivo: {
      title: "VIVO",
      subtitle: "ether1 · Dedicado",
      capacity: 60,
      online: false,
      rx: 0,
      tx: 0,
      detail: "Sem dados"
    },
    webcentro: {
      title: "WEBCENTRO",
      subtitle: "ether2 · Banda larga",
      capacity: 500,
      online: false,
      rx: 0,
      tx: 0,
      detail: "Sem dados"
    }
  };

  for (const line of collectLines()) {
    const p = line.split("|");
    const name = p[0];

    if (name === "LINK_VIVO") {
      links.vivo.online = isTrue(p[2]);
      links.vivo.rx = Number(p[4] || 0);
      links.vivo.tx = Number(p[5] || 0);
      links.vivo.detail = links.vivo.online ? "Link físico ativo" : "Link físico inativo";
    }

    if (name === "LINK_WEBCENTRO") {
      links.webcentro.online = isTrue(p[3]);
      links.webcentro.rx = Number(p[5] || 0);
      links.webcentro.tx = Number(p[6] || 0);
      links.webcentro.detail = links.webcentro.online ? "PPPoE conectado" : "PPPoE desconectado";
    }
  }

  return links;
}

function renderCard(link) {
  const online = link.online === true;

  const rxMbps = online ? formatMbps(link.rx) : "0.00";
  const txMbps = online ? formatMbps(link.tx) : "0.00";

  const rxPct = online ? percent(link.rx, link.capacity) : 0;
  const txPct = online ? percent(link.tx, link.capacity) : 0;

  return `
    <div class="internet-card ${online ? "internet-online" : "internet-offline"}">
      <div class="internet-card-top">
        <div>
          <div class="internet-title">${link.title}</div>
          <div class="internet-subtitle">${link.subtitle}</div>
        </div>
        <div class="internet-capacity">${link.capacity} Mbps</div>
      </div>

      <div class="internet-status-row">
        <span class="internet-dot"></span>
        <span class="${online ? "link-status-ok" : "link-status-down"}">
          ${online ? "ONLINE" : "OFFLINE"}
        </span>
        <span class="internet-detail">${link.detail}</span>
      </div>

      <div class="internet-values">
        <div class="internet-value-box">
          <div class="internet-label">DOWNLOAD</div>
          <div class="internet-number download">${rxMbps} <span>Mbps</span></div>
        </div>

        <div class="internet-value-box">
          <div class="internet-label">UPLOAD</div>
          <div class="internet-number upload">${txMbps} <span>Mbps</span></div>
        </div>
      </div>

      <div class="internet-bars">
        <div class="internet-bar-line">
          <div class="internet-bar-label">
            <span>Uso do Download</span>
            <span>${rxPct.toFixed(1)}%</span>
          </div>
          <div class="internet-bar-bg">
            <div class="internet-bar-fill download" style="width:${rxPct}%"></div>
          </div>
        </div>

        <div class="internet-bar-line">
          <div class="internet-bar-label">
            <span>Uso do Upload</span>
            <span>${txPct.toFixed(1)}%</span>
          </div>
          <div class="internet-bar-bg">
            <div class="internet-bar-fill upload" style="width:${txPct}%"></div>
          </div>
        </div>
      </div>
    </div>
  `;
}

const links = parseLinks();

const root =
  context?.element?.querySelector?.("#internet-links-root") ||
  document.getElementById("internet-links-root");

if (root) {
  root.innerHTML = `
    <div class="internet-panel">
      <div class="internet-header">
        <div>
          <div class="internet-header-title">LINKS DE INTERNET</div>
          <div class="internet-header-subtitle">Monitoramento de tráfego e disponibilidade</div>
        </div>
      </div>

      <div class="internet-grid">
        ${renderCard(links.vivo)}
        ${renderCard(links.webcentro)}
      </div>
    </div>
  `;
}

