function getLastValue(field) {
  const values = field.values;
  const len = values.length ?? 0;

  for (let i = len - 1; i >= 0; i--) {
    const v = values.get ? values.get(i) : values[i];

    if (v !== null && v !== undefined) {
      return v;
    }
  }

  return null;
}

const frames = context?.panelData?.series || [];

const vpn = {
  phase1: null,
  phase2: null
};

for (const frame of frames) {
  const frameName = String(frame.name || "").toLowerCase();

  for (const field of frame.fields || []) {
    if (String(field.type).toLowerCase() === "time") {
      continue;
    }

    const fieldName = String(field.name || "").toLowerCase();
    const displayName = String(field.config?.displayName || "").toLowerCase();
    const fullName = `${frameName} ${fieldName} ${displayName}`;

    const value = getLastValue(field);

    if (value === null || value === undefined) {
      continue;
    }

    if (fullName.includes("phase 1")) {
      vpn.phase1 = Number(value);
    }

    if (fullName.includes("phase 2")) {
      vpn.phase2 = Number(value);
    }
  }
}

function setStatus(elementId, value) {
  const el =
    context?.element?.querySelector?.(`#${elementId}`) ||
    document.getElementById(elementId);

  if (!el) return;

  el.classList.remove("status-online", "status-offline", "status-unknown");

  if (value === 1) {
    el.classList.add("status-online");
    el.innerHTML = `<span class="vpn-dot"></span>ONLINE`;
  } else if (value === 0) {
    el.classList.add("status-offline");
    el.innerHTML = `<span class="vpn-dot"></span>OFFLINE`;
  } else {
    el.classList.add("status-unknown");
    el.innerHTML = `<span class="vpn-dot"></span>SEM DADO`;
  }
}

setStatus("vpn-phase1", vpn.phase1);
setStatus("vpn-phase2", vpn.phase2);

const mainStatus =
  context?.element?.querySelector?.("#vpn-main-status") ||
  document.getElementById("vpn-main-status");

const card =
  context?.element?.querySelector?.(".vpn-card") ||
  document.querySelector(".vpn-card");

if (mainStatus) {
  mainStatus.classList.remove("status-online", "status-offline", "status-unknown");

  if (vpn.phase1 === 1 && vpn.phase2 === 1) {
    mainStatus.classList.add("status-online");
    mainStatus.innerText = "VPN ONLINE";
  } else if (vpn.phase1 === 0 || vpn.phase2 === 0) {
    mainStatus.classList.add("status-offline");
    mainStatus.innerText = "VPN OFFLINE";

    if (card) {
      card.classList.add("offline");
    }
  } else {
    mainStatus.classList.add("status-unknown");
    mainStatus.innerText = "SEM DADO";
  }
}

