function getLastValue(field) {
  const values = field.values;
  const len = values.length ?? 0;

  for (let i = len - 1; i >= 0; i--) {
    const v = values.get ? values.get(i) : values[i];

    if (v !== null && v !== undefined && String(v).trim() !== "") {
      return v;
    }
  }

  return null;
}

function findTemperature() {
  const frames = context?.panelData?.series || [];

  for (const frame of frames) {
    for (const field of frame.fields || []) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const value = getLastValue(field);

      if (value === null || value === undefined) {
        continue;
      }

      const num = Number(String(value).replace(",", "."));

      if (!Number.isNaN(num)) {
        return num;
      }
    }
  }

  return null;
}

const temp = findTemperature();

const valueEl =
  context?.element?.querySelector?.("#temp-value") ||
  document.getElementById("temp-value");

const statusEl =
  context?.element?.querySelector?.("#temp-status") ||
  document.getElementById("temp-status");

const indicatorEl =
  context?.element?.querySelector?.("#temp-indicator") ||
  document.getElementById("temp-indicator");

const barEl =
  context?.element?.querySelector?.("#temp-bar") ||
  document.getElementById("temp-bar");

function setClasses(statusClass, indicatorClass) {
  statusEl?.classList.remove("status-ok", "status-warning", "status-critical", "status-unknown");
  indicatorEl?.classList.remove("indicator-ok", "indicator-warning", "indicator-critical", "indicator-unknown");

  statusEl?.classList.add(statusClass);
  indicatorEl?.classList.add(indicatorClass);
}

if (temp === null) {
  if (valueEl) valueEl.innerText = "-- °C";
  if (statusEl) statusEl.innerText = "SEM DADO";
  if (barEl) {
    barEl.style.width = "0%";
    barEl.style.background = "#999";
  }

  setClasses("status-unknown", "indicator-unknown");
} else {
  const rounded = Math.round(temp * 10) / 10;
  const percent = Math.min(100, Math.max(3, (rounded / 100) * 100));

  if (valueEl) valueEl.innerText = `${rounded} °C`;

  if (barEl) {
    barEl.style.width = `${percent}%`;
  }

  if (rounded >= 80) {
    if (statusEl) statusEl.innerText = "CRÍTICO";
    if (barEl) barEl.style.background = "#ff5f57";
    setClasses("status-critical", "indicator-critical");
  } else if (rounded >= 60) {
    if (statusEl) statusEl.innerText = "ATENÇÃO";
    if (barEl) barEl.style.background = "#f1c40f";
    setClasses("status-warning", "indicator-warning");
  } else {
    if (statusEl) statusEl.innerText = "NORMAL";
    if (barEl) barEl.style.background = "#2ecc71";
    setClasses("status-ok", "indicator-ok");
  }
}

