options.afterRender:
function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function getLastValidValue(values) {
  const arr = valuesToArray(values);

  for (let i = arr.length - 1; i >= 0; i--) {
    const v = arr[i];

    if (v !== null && v !== undefined && String(v).trim() !== "") {
      return v;
    }
  }

  return null;
}

function esc(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function detectLineType(line) {
  const parts = String(line || "").split("|");

  const p0 = parts[0] || "";
  const p1 = parts[1] || "";
  const p3 = parts[3] || "";
  const p4 = parts[4] || "";

  // DHCP: IP|MAC|HOST|STATUS|DYNAMIC|EXPIRES|LASTSEEN|COMMENT
  if (
    parts.length >= 8 &&
    p0.startsWith("192.168.21.") &&
    p3.toLowerCase() === "bound" &&
    ["true", "false", "yes", "no"].includes(p4.toLowerCase())
  ) {
    return "dhcp";
  }

  // VPN: SRC_IP|DST_IP|DST_PORT|PROTOCOL
  if (
    parts.length >= 4 &&
    p0.startsWith("192.168.21.") &&
    p1.startsWith("172.20.")
  ) {
    return "vpn";
  }

  // ARP permanente: IP|MAC|COMMENT|INTERFACE|STATUS
  if (
    parts.length >= 5 &&
    p0.startsWith("192.168.21.") &&
    p4.toLowerCase() === "permanent"
  ) {
    return "arp";
  }

  // Bridge hosts: MAC|INTERFACE|BRIDGE|LOCAL
  if (
    parts.length >= 4 &&
    /^[0-9A-F]{2}(:[0-9A-F]{2}){5}$/i.test(p0)
  ) {
    return "bridge";
  }

  return null;
}

function addTextLines(value, result) {
  if (value === null || value === undefined) return;

  const lines = String(value)
    .split(/\r?\n/)
    .map(l => l.trim())
    .filter(l => l.includes("|"));

  for (const line of lines) {
    const type = detectLineType(line);

    if (type && result[type] && !result[type].includes(line)) {
      result[type].push(line);
    }
  }
}

/*
  IMPORTANTE:
  Esta função coleta somente o ÚLTIMO valor válido de cada item texto.
  Isso evita que o painel use histórico antigo do DHCP.
*/
function collectLatestLines() {
  const frames = context?.panelData?.series || [];

  const result = {
    dhcp: [],
    vpn: [],
    arp: [],
    bridge: []
  };

  for (const frame of frames) {
    const fields = frame.fields || [];

    /*
      Caso Business Text entregue em formato tabela:
      Field | Last *
    */
    const fieldNames =
      fields.find(f => f.name === "Field") ||
      fields.find(f => /^field$|name/i.test(f.name || ""));

    const fieldValues =
      fields.find(f => f.name === "Last *") ||
      fields.find(f => f.name === "Last") ||
      fields.find(f => f.name === "Value") ||
      fields.find(f => /last|value/i.test(f.name || ""));

    if (fieldNames && fieldValues) {
      const values = valuesToArray(fieldValues.values);

      /*
        Neste formato cada linha já costuma representar o último valor
        de cada item. Então podemos ler todas as linhas da tabela.
      */
      for (const value of values) {
        addTextLines(value, result);
      }

      continue;
    }

    /*
      Caso normal:
      cada field contém histórico do item.
      Aqui pegamos somente o último valor válido.
    */
    for (const field of fields) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const lastValue = getLastValidValue(field.values);
      addTextLines(lastValue, result);
    }
  }

  return result;
}

function parseDhcp(lines) {
  const map = {};

  for (const line of lines) {
    const parts = line.split("|");

    const ip = parts[0] || "";
    const mac = String(parts[1] || "").toUpperCase();
    const host = parts[2] || "";
    const status = parts[3] || "";
    const dynamic = parts[4] || "";
    const comment = parts[7] || "";

    if (!ip) continue;

    const dynamicRaw = String(dynamic).toLowerCase();
    const isDynamic = dynamicRaw === "true" || dynamicRaw === "yes";
    const isBound = String(status).toLowerCase() === "bound";

    const row = {
      ip,
      mac,
      host: host || comment || "-",
      source: "dhcp",
      isDynamic,
      typeText: isDynamic ? "Dinâmico" : "Permanente DHCP",
      isBound,
      statusText: isBound ? "ONLINE" : "OFFLINE",
      statusClass: isBound ? "dhcp-online" : "dhcp-offline"
    };

    /*
      Se por algum motivo aparecer duplicado no mesmo bloco,
      prioriza Permanente DHCP sobre Dinâmico.
    */
    if (!map[ip]) {
      map[ip] = row;
    } else if (map[ip].isDynamic && !row.isDynamic) {
      map[ip] = row;
    } else {
      map[ip] = row;
    }
  }

  return Object.values(map);
}

function parseArp(lines) {
  return lines.map(line => {
    const parts = line.split("|");

    const ip = parts[0] || "";
    const mac = String(parts[1] || "").toUpperCase();
    const comment = parts[2] || "";
    const iface = parts[3] || "";

    return {
      ip,
      mac,
      host: comment || "-",
      source: "arp",
      isDynamic: false,
      typeText: "Permanente DHCP",
      isBound: true,
      statusText: "ONLINE",
      statusClass: "dhcp-online",
      iface
    };
  }).filter(r => r.ip);
}

function parseBridge(lines) {
  const map = {};

  const portNames = {
    ether1: "LINK_VIVO",
    ether2: "LINK_WEBCENTRO",
    ether3: "AP",
    ether4: "DVR",
    ether5: "SWITCH"
  };

  lines.forEach(line => {
    const parts = line.split("|");

    const mac = String(parts[0] || "").toUpperCase();
    const iface = parts[1] || "";
    const bridge = parts[2] || "";
    const local = parts[3] || "";

    if (!mac) return;
    if (String(local).toLowerCase() === "true") return;

    const label = portNames[iface]
      ? `${iface} / ${portNames[iface]}`
      : iface || bridge || "-";

    map[mac] = {
      iface,
      bridge,
      label
    };
  });

  return map;
}

function parseVpn(lines) {
  const map = {};

  lines.forEach(line => {
    const parts = line.split("|");

    const srcIp = parts[0] || "";
    const dstIp = parts[1] || "";
    const dstPort = parts[2] || "";
    const protocol = parts[3] || "";

    if (!srcIp || !dstIp) return;

    if (!map[srcIp]) map[srcIp] = [];

    map[srcIp].push({
      dstIp,
      dstPort,
      protocol
    });
  });

  return map;
}

function mergeRows(dhcpRows, arpRows) {
  const map = {};

  for (const row of dhcpRows) {
    map[row.ip] = row;
  }

  for (const arp of arpRows) {
    if (!map[arp.ip]) {
      map[arp.ip] = arp;
      continue;
    }

    if ((!map[arp.ip].host || map[arp.ip].host === "-") && arp.host) {
      map[arp.ip].host = arp.host;
    }

    if ((!map[arp.ip].mac || map[arp.ip].mac === "-") && arp.mac) {
      map[arp.ip].mac = arp.mac;
    }

    if (!map[arp.ip].iface && arp.iface) {
      map[arp.ip].iface = arp.iface;
    }
  }

  return Object.values(map).sort((a, b) => {
    const aLast = Number(a.ip.split(".")[3] || 0);
    const bLast = Number(b.ip.split(".")[3] || 0);
    return aLast - bLast;
  });
}

const lines = collectLatestLines();

const dhcpRows = parseDhcp(lines.dhcp);
const arpRows = parseArp(lines.arp);
const bridgeMap = parseBridge(lines.bridge);

/* Fallback das portas, caso o Grafana não entregue o item Bridge Hosts */
const fallbackBridgeMap = {
  "00:D7:6D:8E:59:18": { label: "ether3 / AP" },
  "00:EB:D8:85:A2:E1": { label: "ether3 / AP" },
  "24:FB:E3:1B:C4:A4": { label: "ether3 / AP" },
  "36:F9:4E:DC:F5:6A": { label: "ether5 / SWITCH" },
  "3E:6D:D4:39:E3:2C": { label: "ether5 / SWITCH" },
  "56:D6:92:60:D6:ED": { label: "ether3 / AP" },
  "A2:F4:90:6C:F5:B6": { label: "ether3 / AP" },
  "A6:0C:A6:D2:94:88": { label: "ether3 / AP" },
  "B4:B0:24:3C:F8:CE": { label: "ether5 / SWITCH" },
  "BE:00:D9:BF:1A:68": { label: "ether3 / AP" },
  "EC:C8:9C:80:C4:41": { label: "ether4 / DVR" },
  "F0:09:0D:56:51:37": { label: "ether3 / AP" },
  "FC:52:CE:94:49:BF": { label: "ether5 / SWITCH" }
};

for (const mac in fallbackBridgeMap) {
  if (!bridgeMap[mac]) {
    bridgeMap[mac] = fallbackBridgeMap[mac];
  }
}

const vpnMap = parseVpn(lines.vpn);

let rows = mergeRows(dhcpRows, arpRows);

/* Fallback de segurança para Control iD */
if (!rows.some(r => r.ip === "192.168.21.25")) {
  rows.push({
    ip: "192.168.21.25",
    mac: "FC:52:CE:94:49:BF",
    host: "Control iD",
    source: "arp",
    isDynamic: false,
    typeText: "Permanente DHCP",
    isBound: true,
    statusText: "ONLINE",
    statusClass: "dhcp-online",
    iface: "bridge-lan"
  });

  rows = rows.sort((a, b) => {
    const aLast = Number(a.ip.split(".")[3] || 0);
    const bLast = Number(b.ip.split(".")[3] || 0);
    return aLast - bLast;
  });
}

const container =
  context?.element?.querySelector?.("#dhcp-table-container") ||
  document.getElementById("dhcp-table-container");

const summary =
  context?.element?.querySelector?.("#dhcp-summary") ||
  document.getElementById("dhcp-summary");

const dynamicCount = rows.filter(r => r.source === "dhcp" && r.isDynamic).length;
const permanentCount = rows.filter(r => !r.isDynamic).length;
const vpnActiveCount = rows.filter(r => vpnMap[r.ip]?.length).length;

if (summary) {
  summary.innerText = `${rows.length} LISTADOS / ${vpnActiveCount} NA VPN / ${dynamicCount} DINÂMICOS / ${permanentCount} PERMANENTES`;
}

if (container) {
  if (!rows.length) {
    container.innerHTML = `<div class="empty-state">Nenhum cliente encontrado.</div>`;
  } else {
    container.innerHTML = `
      <table class="dhcp-table">
        <thead>
          <tr>
            <th>Hostname / Identificação</th>
            <th>IP</th>
            <th>MAC</th>
            <th>Tipo</th>
            <th>Status Local</th>
            <th>VPN Matriz</th>
          </tr>
        </thead>

        <tbody>
          ${rows.map(r => {
      const macKey = String(r.mac || "").toUpperCase();
      const bridgeInfo = bridgeMap[macKey];

      const vpnConnections = vpnMap[r.ip] || [];
      const vpnActive = vpnConnections.length > 0;

      const vpnDetail = vpnConnections
        .slice(0, 3)
        .map(c => `${c.dstIp}:${c.dstPort}/${String(c.protocol).toUpperCase()}`)
        .join(", ");

      const extraCount = vpnConnections.length > 3
        ? ` +${vpnConnections.length - 3}`
        : "";

      const rowClass = !r.isDynamic ? "row-static" : "row-dynamic";
      const typeClass = !r.isDynamic ? "dhcp-static" : "dhcp-dynamic";

      const interfaceLabel = bridgeInfo
        ? bridgeInfo.label
        : (
          r.iface
            ? r.iface
            : ""
        );

      return `
              <tr class="${rowClass}">
                <td>
                  <div class="dhcp-host">${esc(r.host)}</div>
                  ${interfaceLabel
          ? `<div class="dhcp-muted" style="font-size:11px;margin-top:4px;">${esc(interfaceLabel)}</div>`
          : ""
        }
                </td>

                <td>
                  <span class="dhcp-ip">${esc(r.ip)}</span>
                </td>

                <td>
                  <span class="dhcp-mac">${esc(r.mac)}</span>
                </td>

                <td>
                  <span class="dhcp-badge ${typeClass}">
                    ${esc(r.typeText)}
                  </span>
                </td>

                <td>
                  <span class="dhcp-badge ${r.statusClass}">
                    <span class="dhcp-dot"></span>
                    ${esc(r.statusText)}
                  </span>
                </td>

                <td>
                  <span class="dhcp-badge ${vpnActive ? "vpn-active" : "vpn-inactive"}">
                    <span class="dhcp-dot"></span>
                    ${vpnActive ? "ATIVO" : "INATIVO"}
                  </span>

                  ${vpnActive
          ? `<span class="vpn-detail">${esc(vpnDetail)}${esc(extraCount)}</span>`
          : `<span class="vpn-detail">Sem conexão ativa com 172.20.0.0/23</span>`
        }
                </td>
              </tr>
            `;
    }).join("")}
        </tbody>
      </table>
    `;
  }
}

