options.afterRender:
function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function parseBps(value) {
  const raw = String(value ?? "").trim().toLowerCase();

  if (!raw) return 0;

  if (raw.endsWith("kbps")) {
    return Number(raw.replace(/[^\d.]/g, "") || 0) * 1000;
  }

  if (raw.endsWith("mbps")) {
    return Number(raw.replace(/[^\d.]/g, "") || 0) * 1000000;
  }

  if (raw.endsWith("gbps")) {
    return Number(raw.replace(/[^\d.]/g, "") || 0) * 1000000000;
  }

  return Number(raw.replace(/[^\d]/g, "") || 0);
}

function formatBps(value) {
  const bps = Number(value || 0);

  if (bps >= 1000000000) {
    return `${(bps / 1000000000).toFixed(2)} Gbps`;
  }

  if (bps >= 1000000) {
    return `${(bps / 1000000).toFixed(2)} Mbps`;
  }

  if (bps >= 1000) {
    return `${(bps / 1000).toFixed(1)} Kbps`;
  }

  return `${Math.round(bps)} bps`;
}

function collectLines() {
  const frames = context?.panelData?.series || [];
  const lines = [];

  for (const frame of frames) {
    for (const field of frame.fields || []) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const values = valuesToArray(field.values);

      for (const value of values) {
        if (value === null || value === undefined) {
          continue;
        }

        const splitLines = String(value)
          .split(/\r?\n/)
          .map(l => l.trim())
          .filter(l => l.startsWith("LINK_") && l.includes("|"));

        for (const line of splitLines) {
          lines.push(line);
        }
      }
    }
  }

  return lines;
}

function parseFailover(lines) {
  const map = {};

  for (const line of lines) {
    const parts = line.split("|");

    /*
      Formato esperado:
      LINK_VIVO|ether1|1|317696|655680
      LINK_WEBCENTRO|ether2|1|53040|19336

      Campo 0 = Link
      Campo 1 = Interface
      Campo 2 = Rota ativa: 1 ou 0
      Campo 3 = RX bps
      Campo 4 = TX bps
    */

    const name = parts[0] || "";
    const iface = parts[1] || "";
    const routeActive = Number(parts[2] || 0) > 0;
    const rx = parseBps(parts[3]);
    const tx = parseBps(parts[4]);

    if (!name) {
      continue;
    }

    map[name] = {
      name,
      iface,
      routeActive,
      rx,
      tx,
      total: rx + tx
    };
  }

  return map;
}

const lines = collectLines();
const links = parseFailover(lines);

const vivo = links["LINK_VIVO"];
const web = links["LINK_WEBCENTRO"];

const badge =
  context?.element?.querySelector?.("#fail-badge") ||
  document.getElementById("fail-badge");

const detail =
  context?.element?.querySelector?.("#fail-detail") ||
  document.getElementById("fail-detail");

function setStatus(text, cls, detailText) {
  if (badge) {
    badge.classList.remove("badge-ok", "badge-warning", "badge-critical", "badge-unknown");
    badge.classList.add(cls);
    badge.innerText = text;
  }

  if (detail) {
    detail.innerText = detailText;
  }
}

if (!vivo && !web) {
  setStatus(
    "SEM DADO",
    "badge-unknown",
    "Nenhum dado recebido do Zabbix."
  );
} else {
  const vivoActive = vivo?.routeActive === true;
  const webActive = web?.routeActive === true;

  const vivoTraffic = vivo?.total || 0;
  const webTraffic = web?.total || 0;

  const saidaAtual = webTraffic > vivoTraffic ? "LINK_WEBCENTRO" : "LINK_VIVO";
  const maiorTrafego = Math.max(vivoTraffic, webTraffic);

  if (!vivoActive && !webActive) {
    setStatus(
      "DOWN",
      "badge-critical",
      "Nenhuma rota de internet ativa."
    );
  } else if (!vivoActive && webActive) {
    setStatus(
      "FAILOVER",
      "badge-warning",
      `VIVO indisponível · saída atual: LINK_WEBCENTRO · ${formatBps(webTraffic)}`
    );
  } else if (vivoActive && !webActive) {
    setStatus(
      "SEM BACKUP",
      "badge-warning",
      "Saída atual: LINK_VIVO · WEBCENTRO sem rota ativa"
    );
  } else if (vivoActive && webActive) {
    setStatus(
      "NORMAL",
      "badge-ok",
      `VIVO e WEBCENTRO ativos · saída predominante: ${saidaAtual} · ${formatBps(maiorTrafego)}`
    );
  } else {
    setStatus(
      "SEM DADO",
      "badge-unknown",
      "Não foi possível interpretar o estado dos links."
    );
  }
}

