function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function formatBytes(bytes) {
  const value = Number(bytes || 0);

  if (value >= 1024 ** 3) {
    return `${(value / 1024 ** 3).toFixed(2)} GB`;
  }

  if (value >= 1024 ** 2) {
    return `${(value / 1024 ** 2).toFixed(2)} MB`;
  }

  if (value >= 1024) {
    return `${(value / 1024).toFixed(1)} KB`;
  }

  return `${value} B`;
}

function collectLines() {
  const frames = context?.panelData?.series || [];
  const lines = [];

  for (const frame of frames) {
    for (const field of frame.fields || []) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const values = valuesToArray(field.values);

      for (const value of values) {
        if (value === null || value === undefined) {
          continue;
        }

        const splitLines = String(value)
          .split(/\r?\n/)
          .map(l => l.trim())
          .filter(l => l.startsWith("MANGLE_") && l.includes("|"));

        for (const line of splitLines) {
          lines.push(line);
        }
      }
    }
  }

  return lines;
}

function parseMangle(lines) {
  const map = {};

  for (const line of lines) {
    const parts = line.split("|");

    const name = parts[0] || "";
    const routingMark = parts[1] || "";
    const disabledRaw = parts[2] || "";
    const bytes = Number(String(parts[3] || "0").replace(/[^\d]/g, "") || 0);
    const packets = Number(String(parts[4] || "0").replace(/[^\d]/g, "") || 0);

    if (!name) continue;

    map[name] = {
      name,
      routingMark,
      disabledRaw,
      disabled: String(disabledRaw).toLowerCase() === "true",
      missing: String(disabledRaw).toLowerCase() === "missing",
      bytes,
      packets
    };
  }

  return map;
}

const lines = collectLines();
const mangle = parseMangle(lines);

const dvr = mangle["MANGLE_DVR_VIVO"];
const usuarios = mangle["MANGLE_USUARIOS_WEBCENTRO"];

const badge =
  context?.element?.querySelector?.("#mangle-badge") ||
  document.getElementById("mangle-badge");

const detail =
  context?.element?.querySelector?.("#mangle-detail") ||
  document.getElementById("mangle-detail");

function setStatus(text, cls, detailText) {
  if (badge) {
    badge.classList.remove("badge-ok", "badge-warning", "badge-critical", "badge-unknown");
    badge.classList.add(cls);
    badge.innerText = text;
  }

  if (detail) {
    detail.innerText = detailText;
  }
}

if (!dvr && !usuarios) {
  setStatus("SEM DADO", "badge-unknown", "Nenhum dado recebido do Zabbix.");
} else if (!usuarios || usuarios.missing) {
  setStatus("ERRO", "badge-critical", "Regra de usuários para WEBCENTRO não encontrada.");
} else if (usuarios.disabled) {
  setStatus("ATENÇÃO", "badge-warning", "Regra de usuários para WEBCENTRO está desabilitada.");
} else if (usuarios.bytes <= 0 || usuarios.packets <= 0) {
  setStatus("ATENÇÃO", "badge-warning", "Regra de usuários ativa, mas sem contador de tráfego.");
} else {
  const dvrText = !dvr || dvr.missing
    ? "DVR VIVO: regra ausente"
    : dvr.disabled
      ? "DVR VIVO: em rota"
      : `DVR VIVO: ativo · ${formatBytes(dvr.bytes)}`;

  setStatus(
    "NORMAL",
    "badge-ok",
    `Usuários → WEBCENTRO · ${formatBytes(usuarios.bytes)} · ${dvrText}`
  );
}

