options.afterRender:
function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function collectLines() {
  const frames = context?.panelData?.series || [];
  const lines = [];

  for (const frame of frames) {
    for (const field of frame.fields || []) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const values = valuesToArray(field.values);

      for (const value of values) {
        if (value === null || value === undefined) {
          continue;
        }

        String(value)
          .split(/\r?\n/)
          .map(l => l.trim())
          .filter(l => l.startsWith("DDNS_RJ|"))
          .forEach(l => lines.push(l));
      }
    }
  }

  return lines;
}

function parseDdns(lines) {
  if (!lines.length) return null;

  const parts = lines[lines.length - 1].split("|");

  const host = parts[1] || "";
  const publicIP = parts[2] || "";

  // Formato novo:
  // DDNS_RJ|host|publicIP|dns1|dns2|dns3|schedulerDisabled
  if (parts.length >= 7) {
    return {
      host,
      publicIP,
      dns1: parts[3] || "",
      dns2: parts[4] || "",
      dns3: parts[5] || "",
      schedulerDisabled: String(parts[6] || "").toLowerCase()
    };
  }

  // Formato antigo:
  // DDNS_RJ|host|publicIP|resolvedIP|schedulerDisabled
  return {
    host,
    publicIP,
    dns1: parts[3] || "",
    dns2: "",
    dns3: "",
    schedulerDisabled: String(parts[4] || "").toLowerCase()
  };
}

const ddns = parseDdns(collectLines());

const badge =
  context?.element?.querySelector?.("#ddns-badge") ||
  document.getElementById("ddns-badge");

const detail =
  context?.element?.querySelector?.("#ddns-detail") ||
  document.getElementById("ddns-detail");

function setStatus(text, cls, detailText) {
  if (badge) {
    badge.classList.remove(
      "badge-ok",
      "badge-warning",
      "badge-critical",
      "badge-unknown"
    );

    badge.classList.add(cls);
    badge.innerText = text;
  }

  if (detail) {
    detail.innerText = detailText;
  }
}

if (!ddns) {
  setStatus(
    "SEM DADO",
    "badge-unknown",
    "Nenhum dado recebido do Zabbix."
  );
} else if (!ddns.publicIP) {
  setStatus(
    "ERRO",
    "badge-critical",
    "IP de referência não encontrado."
  );
} else if (ddns.schedulerDisabled === "true") {
  setStatus(
    "ATENÇÃO",
    "badge-warning",
    `${ddns.host} · Scheduler desativado`
  );
} else {
  const dnsList = [ddns.dns1, ddns.dns2, ddns.dns3].filter(Boolean);
  const okCount = dnsList.filter(ip => ip === ddns.publicIP).length;

  if (!dnsList.length) {
    setStatus(
      "ERRO",
      "badge-critical",
      `${ddns.host} · DNS não resolveu`
    );
  } else if (dnsList.length === 1) {
    if (okCount === 1) {
      setStatus(
        "NORMAL",
        "badge-ok",
        `${ddns.host} · DNS OK · Scheduler ativo`
      );
    } else {
      setStatus(
        "DIVERGENTE",
        "badge-warning",
        `${ddns.host} · DNS divergente`
      );
    }
  } else if (okCount >= 2) {
    setStatus(
      "NORMAL",
      "badge-ok",
      `${ddns.host} · DNS OK · Scheduler ativo`
    );
  } else if (okCount === 1) {
    setStatus(
      "ATENÇÃO",
      "badge-warning",
      `${ddns.host} · Propagação parcial`
    );
  } else {
    setStatus(
      "DIVERGENTE",
      "badge-warning",
      `${ddns.host} · DNS divergente`
    );
  }
}

