options.afterRender:
const EVENT_LIMIT = 15;

function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function esc(value) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function formatDateBR(value) {
  const raw = String(value || "").trim();

  const m = raw.match(/^(\d{4})-(\d{2})-(\d{2})\s+(\d{2}:\d{2}:\d{2})$/);
  if (m) {
    return `${m[3]}/${m[2]}/${m[1]} ${m[4]}`;
  }

  return raw;
}

function parseDateValue(value) {
  const raw = String(value || "").trim();
  const d = new Date(raw.replace(" ", "T"));
  return isNaN(d.getTime()) ? 0 : d.getTime();
}

function collectRawText() {
  const frames = context?.panelData?.series || [];
  const chunks = [];

  for (const frame of frames) {
    for (const field of frame.fields || []) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const values = valuesToArray(field.values);

      for (const value of values) {
        if (value === null || value === undefined) {
          continue;
        }

        const text = String(value).trim();

        if (text.includes("|")) {
          chunks.push(text);
        }
      }
    }
  }

  return chunks.join("\n");
}

function parseLogs(rawText) {
  const map = new Map();

  String(rawText || "")
    .split(/\r?\n/)
    .map(l => l.trim())
    .filter(l => l.includes("|"))
    .forEach(line => {
      const parts = line.split("|");

      const time = parts[0] || "";
      const topics = parts[1] || "";
      const message = parts.slice(2).join("|") || "";

      if (!time || !message) {
        return;
      }

      const key = `${time}|${topics}|${message}`;

      if (!map.has(key)) {
        map.set(key, {
          time,
          topics,
          message,
          sort: parseDateValue(time)
        });
      }
    });

  return Array.from(map.values())
    .sort((a, b) => b.sort - a.sort)
    .slice(0, EVENT_LIMIT);
}

function parseDhcpMessage(msg) {
  const text = String(msg || "");

  const assigned = text.match(/assigned\s+([0-9.]+)\s+for\s+([A-Fa-f0-9:]+)\s*(.*)?/);
  if (assigned) {
    return {
      action: "assigned",
      ip: assigned[1] || "",
      mac: assigned[2] || "",
      host: String(assigned[3] || "").trim() || "Dispositivo sem hostname"
    };
  }

  const deassigned = text.match(/deassigned\s+([0-9.]+)\s+for\s+([A-Fa-f0-9:]+)\s*(.*)?/);
  if (deassigned) {
    return {
      action: "deassigned",
      ip: deassigned[1] || "",
      mac: deassigned[2] || "",
      host: String(deassigned[3] || "").trim() || "Dispositivo sem hostname"
    };
  }

  return null;
}

function extractPeer(msg) {
  const text = String(msg || "");
  const match = text.match(/([0-9]{1,3}(?:\.[0-9]{1,3}){3})\[\d+\]/);
  return match ? match[1] : "";
}

function friendlyEvent(log) {
  const topics = String(log.topics || "");
  const msg = String(log.message || "");
  const topicsLower = topics.toLowerCase();
  const msgLower = msg.toLowerCase();

  /*
    PPPoE / Link Internet
    Qualquer evento ppp/pppoe aparece como LINK vermelho.
  */
  if (
    topicsLower.includes("ppp") ||
    topicsLower.includes("pppoe") ||
    msgLower.includes("pppoe-webcentro")
  ) {
    if (
      msgLower.includes("disconnected") ||
      msgLower.includes("terminating") ||
      msgLower.includes("failed") ||
      msgLower.includes("timeout")
    ) {
      return {
        badge: "LINK",
        badgeClass: "badge-link",
        title: "Link WEBCENTRO offline",
        detail: msg,
        weight: 5
      };
    }

    if (
      msgLower.includes("initializing") ||
      msgLower.includes("connecting")
    ) {
      return {
        badge: "LINK",
        badgeClass: "badge-link",
        title: "Tentativa de conexão WEBCENTRO",
        detail: msg,
        weight: 4
      };
    }

    if (
      msgLower.includes("connected") ||
      msgLower.includes("authenticated")
    ) {
      return {
        badge: "LINK",
        badgeClass: "badge-link",
        title: "Link WEBCENTRO conectado",
        detail: msg,
        weight: 3
      };
    }

    return {
      badge: "LINK",
      badgeClass: "badge-link",
      title: "Evento do link WEBCENTRO",
      detail: msg,
      weight: 4
    };
  }

  if (topicsLower.includes("dhcp")) {
    const dhcp = parseDhcpMessage(msg);

    if (dhcp?.action === "assigned") {
      return {
        badge: "DHCP",
        badgeClass: "badge-dhcp",
        title: "Cliente conectado na LAN",
        detail: `${dhcp.host} · IP ${dhcp.ip} · MAC ${dhcp.mac}`,
        weight: 2
      };
    }

    if (dhcp?.action === "deassigned") {
      return {
        badge: "DHCP",
        badgeClass: "badge-dhcp",
        title: "Cliente desconectado da LAN",
        detail: `${dhcp.host} · IP ${dhcp.ip} · MAC ${dhcp.mac}`,
        weight: 2
      };
    }

    return {
      badge: "DHCP",
      badgeClass: "badge-dhcp",
      title: "Evento DHCP",
      detail: msg,
      weight: 2
    };
  }

  if (topicsLower.includes("ipsec") || msgLower.includes("ipsec")) {
    if (msgLower.includes("no proposal chosen")) {
      return {
        badge: "IPSEC",
        badgeClass: "badge-ipsec",
        title: "IPsec sem proposal compatível",
        detail: "Negociação recebida sem proposta válida",
        weight: 4
      };
    }

    if (msgLower.includes("phase1 negotiation failed")) {
      const peer = extractPeer(msg);

      return {
        badge: "IPSEC",
        badgeClass: "badge-ipsec",
        title: "Falha na negociação IPsec Phase 1",
        detail: peer ? `Peer remoto detectado: ${peer}` : msg,
        weight: 4
      };
    }

    if (msgLower.includes("peer authorized")) {
      return {
        badge: "IPSEC",
        badgeClass: "badge-ipsec-ok",
        title: "VPN IPsec autorizada",
        detail: msg,
        weight: 2
      };
    }

    return {
      badge: "IPSEC",
      badgeClass: "badge-ipsec",
      title: "Evento IPsec",
      detail: msg,
      weight: 3
    };
  }

  if (msgLower.includes("script error") || topicsLower.includes("script")) {
    return {
      badge: "SCRIPT",
      badgeClass: "badge-script",
      title: "Erro em script/item SSH",
      detail: "Consulta tentando ler objeto inexistente",
      weight: 5
    };
  }

  if (msgLower.includes("login failure")) {
    return {
      badge: "ERRO",
      badgeClass: "badge-error",
      title: "Erro no MikroTik",
      detail: msg,
      weight: 5
    };
  }

  if (topicsLower.includes("error")) {
    return {
      badge: "ERRO",
      badgeClass: "badge-error",
      title: "Erro no MikroTik",
      detail: msg,
      weight: 5
    };
  }

  if (topicsLower.includes("warning")) {
    return {
      badge: "AVISO",
      badgeClass: "badge-warning",
      title: "Aviso do MikroTik",
      detail: msg,
      weight: 4
    };
  }

  if (topicsLower.includes("interface")) {
    return {
      badge: "LINK",
      badgeClass: "badge-link",
      title: "Evento de interface",
      detail: msg,
      weight: 3
    };
  }

  return {
    badge: "INFO",
    badgeClass: "badge-info",
    title: "Evento informativo",
    detail: msg,
    weight: 1
  };
}

function renderPanel() {
  const root =
    context?.element?.querySelector?.("#mklog-root") ||
    document.getElementById("mklog-root");

  if (!root) {
    return;
  }

  const logs = parseLogs(collectRawText());
  const enriched = logs.map(log => ({
    ...log,
    event: friendlyEvent(log)
  }));

  const dhcpCount = enriched.filter(e => e.event.badge === "DHCP").length;
  const eventCount = enriched.length;

  if (!eventCount) {
    root.innerHTML = `
      <div class="mklog-panel">
        <div class="mklog-header">
          <div>
            <div class="mklog-title">EVENTOS RECENTES</div>
            <div class="mklog-subtitle">Logs importantes do MikroTik RJ</div>
          </div>
          <div class="mklog-summary summary-ok">SEM EVENTOS</div>
        </div>

        <div class="mklog-empty">
          <div class="mklog-empty-title">✅ Nenhum evento recente</div>
          <div class="mklog-empty-subtitle">Sem logs importantes retornados pelo MikroTik</div>
        </div>
      </div>
    `;

    return;
  }

  root.innerHTML = `
    <div class="mklog-panel">
      <div class="mklog-header">
        <div>
          <div class="mklog-title">EVENTOS RECENTES</div>
          <div class="mklog-subtitle">Logs importantes do MikroTik RJ</div>
        </div>
        <div class="mklog-summary">
          ${eventCount} EVENTOS / ${dhcpCount} DHCP
        </div>
      </div>

      <div class="mklog-list">
        ${enriched.map(item => `
          <div class="mklog-row">
            <div class="mklog-time">${esc(formatDateBR(item.time))}</div>

            <div class="mklog-badge ${item.event.badgeClass}">
              ${esc(item.event.badge)}
            </div>

            <div class="mklog-main">
              <div class="mklog-main-title">${esc(item.event.title)}</div>
              <div class="mklog-main-detail">${esc(item.event.detail)}</div>
            </div>
          </div>
        `).join("")}
      </div>
    </div>
  `;
}

renderPanel();

