options.afterRender:
const CLIENT_LIMIT = 20;
const DEST_LIMIT_PER_CLIENT = 3;
const SERVICE_LIMIT_PER_CLIENT = 4;

function valuesToArray(values) {
  if (!values) return [];

  const len = values.length ?? 0;
  const arr = [];

  for (let i = 0; i < len; i++) {
    arr.push(values.get ? values.get(i) : values[i]);
  }

  return arr;
}

function getLastValidValue(values) {
  const arr = valuesToArray(values);

  for (let i = arr.length - 1; i >= 0; i--) {
    const v = arr[i];

    if (v !== null && v !== undefined && String(v).trim() !== "") {
      return v;
    }
  }

  return null;
}

function esc(value) {
  return String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function isIp(value) {
  return /^\d{1,3}(\.\d{1,3}){3}$/.test(String(value || "").trim());
}

function normalizeIpWithPort(value) {
  return String(value || "").split(":")[0].trim();
}

function detectLineType(line) {
  const parts = String(line || "").split("|");

  const p0 = parts[0] || "";
  const p1 = parts[1] || "";
  const p3 = parts[3] || "";
  const p4 = parts[4] || "";

  /*
    TOP DESTINOS:
    SRC_IP|DST_IP|DST_PORT|PROTOCOL|ORIG_BYTES|REPL_BYTES|ORIG_RATE|REPL_RATE
  */
  if (
    parts.length >= 8 &&
    p0.startsWith("192.168.21.") &&
    isIp(normalizeIpWithPort(p1))
  ) {
    return "top";
  }

  /*
    DHCP:
    IP|MAC|HOST|STATUS|DYNAMIC|EXPIRES|LASTSEEN|COMMENT
  */
  if (
    parts.length >= 8 &&
    p0.startsWith("192.168.21.") &&
    p3.toLowerCase() === "bound" &&
    ["true", "false", "yes", "no"].includes(p4.toLowerCase())
  ) {
    return "dhcp";
  }

  /*
    ARP:
    IP|MAC|COMMENT|INTERFACE|STATUS
  */
  if (
    parts.length >= 5 &&
    p0.startsWith("192.168.21.") &&
    p4.toLowerCase() === "permanent"
  ) {
    return "arp";
  }

  return null;
}

function addTextLines(value, result) {
  if (value === null || value === undefined) return;

  const lines = String(value)
    .split(/\r?\n/)
    .map(l => l.trim())
    .filter(l => l.includes("|"));

  for (const line of lines) {
    const type = detectLineType(line);

    if (type && result[type] && !result[type].includes(line)) {
      result[type].push(line);
    }
  }
}

function collectLatestLines() {
  const frames = context?.panelData?.series || [];

  const result = {
    top: [],
    dhcp: [],
    arp: []
  };

  for (const frame of frames) {
    const fields = frame.fields || [];

    const fieldNames =
      fields.find(f => f.name === "Field") ||
      fields.find(f => /^field$|name/i.test(f.name || ""));

    const fieldValues =
      fields.find(f => f.name === "Last *") ||
      fields.find(f => f.name === "Last") ||
      fields.find(f => f.name === "Value") ||
      fields.find(f => /last|value/i.test(f.name || ""));

    if (fieldNames && fieldValues) {
      const values = valuesToArray(fieldValues.values);

      for (const value of values) {
        addTextLines(value, result);
      }

      continue;
    }

    for (const field of fields) {
      if (String(field.type).toLowerCase() === "time") {
        continue;
      }

      const lastValue = getLastValidValue(field.values);
      addTextLines(lastValue, result);
    }
  }

  return result;
}

function parseNumber(value) {
  return Number(String(value || "0").replace(/[^\d]/g, "") || 0);
}

function classifyDestination(dstIp, port, protocol, srcIp) {
  const ip = String(dstIp || "");
  const p = String(port || "");
  const proto = String(protocol || "").toUpperCase();

  if (ip.startsWith("172.20.")) {
    return {
      name: "VPN Matriz",
      className: "svc-vpn"
    };
  }

  if (
    ip.startsWith("10.") ||
    ip.startsWith("192.168.") ||
    ip.startsWith("255.")
  ) {
    return {
      name: "Rede local",
      className: "svc-local"
    };
  }

  if (
    ip.startsWith("142.250.") ||
    ip.startsWith("142.251.") ||
    ip.startsWith("172.217.") ||
    ip.startsWith("216.239.") ||
    ip.startsWith("64.233.") ||
    ip.startsWith("108.177.") ||
    ip === "8.8.8.8" ||
    ip === "8.8.4.4"
  ) {
    return {
      name: "Google / YouTube",
      className: "svc-google"
    };
  }

  if (
    ip.startsWith("31.13.") ||
    ip.startsWith("57.144.") ||
    ip.startsWith("57.145.") ||
    ip.startsWith("157.240.")
  ) {
    return {
      name: "Meta / WhatsApp",
      className: "svc-meta"
    };
  }

  if (ip.startsWith("17.")) {
    return {
      name: "Apple",
      className: "svc-apple"
    };
  }

  if (
    ip.startsWith("20.") ||
    ip.startsWith("40.") ||
    ip.startsWith("52.123.") ||
    ip.startsWith("104.41.") ||
    ip.startsWith("172.172.")
  ) {
    return {
      name: "Microsoft / Azure",
      className: "svc-ms"
    };
  }

  if (
    ip.startsWith("44.") ||
    ip.startsWith("52.") ||
    ip.startsWith("54.") ||
    ip.startsWith("18.") ||
    ip.startsWith("3.") ||
    ip.startsWith("15.")
  ) {
    return {
      name: "AWS / Cloud",
      className: "svc-cloud"
    };
  }

  if (ip === "208.67.222.222") {
    return {
      name: "OpenDNS",
      className: "svc-dns"
    };
  }

  if (srcIp === "192.168.21.25" || p === "31011") {
    return {
      name: "Control iD Cloud",
      className: "svc-control"
    };
  }

  if (p === "443" && proto === "UDP") {
    return {
      name: "HTTPS / QUIC",
      className: "svc-https"
    };
  }

  if (p === "443") {
    return {
      name: "HTTPS",
      className: "svc-https"
    };
  }

  if (p === "80") {
    return {
      name: "HTTP",
      className: "svc-http"
    };
  }

  if (p === "53") {
    return {
      name: "DNS",
      className: "svc-dns"
    };
  }

  return {
    name: "Outro destino",
    className: "svc-other"
  };
}

function parseClientsNames(dhcpLines, arpLines) {
  const map = {};

  for (const line of dhcpLines) {
    const parts = line.split("|");

    const ip = parts[0] || "";
    const host = parts[2] || "";
    const comment = parts[7] || "";

    if (!ip) continue;

    const name = host || comment || "";

    if (name && name !== "-") {
      map[ip] = name;
    }
  }

  for (const line of arpLines) {
    const parts = line.split("|");

    const ip = parts[0] || "";
    const comment = parts[2] || "";

    if (!ip) continue;

    if (!map[ip] && comment && comment !== "-") {
      map[ip] = comment;
    }
  }

  return map;
}

function parseTopGrouped(topLines, clientNames) {
  const clients = {};

  for (const line of topLines) {
    const parts = line.split("|");

    const srcIp = normalizeIpWithPort(parts[0]);
    const dstIp = normalizeIpWithPort(parts[1]);
    const dstPort = parts[2] || "";
    const protocol = parts[3] || "";
    const upload = parseNumber(parts[4]);
    const download = parseNumber(parts[5]);

    if (!srcIp || !dstIp) continue;

    const service = classifyDestination(dstIp, dstPort, protocol, srcIp);
    const destKey = `${dstIp}|${dstPort}|${protocol}`;
    const serviceKey = service.name;

    if (!clients[srcIp]) {
      clients[srcIp] = {
        ip: srcIp,
        name: clientNames[srcIp] || srcIp,
        connections: 0,
        totalBytes: 0,
        destinations: {},
        services: {}
      };
    }

    const client = clients[srcIp];

    client.connections += 1;
    client.totalBytes += upload + download;

    if (!client.destinations[destKey]) {
      client.destinations[destKey] = {
        dstIp,
        dstPort,
        protocol,
        serviceName: service.name,
        serviceClass: service.className,
        count: 0
      };
    }

    client.destinations[destKey].count += 1;

    if (!client.services[serviceKey]) {
      client.services[serviceKey] = {
        name: service.name,
        className: service.className,
        count: 0
      };
    }

    client.services[serviceKey].count += 1;
  }

  return Object.values(clients).sort((a, b) => {
    if (b.connections !== a.connections) {
      return b.connections - a.connections;
    }

    return b.totalBytes - a.totalBytes;
  });
}

const lines = collectLatestLines();
const clientNames = parseClientsNames(lines.dhcp, lines.arp);

const allClients = parseTopGrouped(lines.top, clientNames);
const clients = allClients.slice(0, CLIENT_LIMIT);

const totalConnections = lines.top.length;
const totalClients = allClients.length;
const totalDestinations = new Set(
  lines.top.map(line => {
    const parts = line.split("|");
    return normalizeIpWithPort(parts[1]);
  }).filter(Boolean)
).size;

const container =
  context?.element?.querySelector?.("#topdest-table-container") ||
  document.getElementById("topdest-table-container");

const summary =
  context?.element?.querySelector?.("#topdest-summary") ||
  document.getElementById("topdest-summary");

if (summary) {
  summary.innerText = `${totalConnections} CONEXÕES / ${totalClients} CLIENTES / ${totalDestinations} DESTINOS`;
}

if (container) {
  if (!clients.length) {
    container.innerHTML = `<div class="topdest-empty">Nenhum destino ativo encontrado.</div>`;
  } else {
    container.innerHTML = `
      <table class="topdest-table">
        <thead>
          <tr>
            <th>#</th>
            <th>Cliente</th>
            <th>Destinos</th>
            <th>Serviços prováveis</th>
            <th>Conexões</th>
          </tr>
        </thead>

        <tbody>
          ${clients.map((client, index) => {
      const destinations = Object.values(client.destinations)
        .sort((a, b) => b.count - a.count);

      const services = Object.values(client.services)
        .sort((a, b) => b.count - a.count);

      const visibleDestinations = destinations.slice(0, DEST_LIMIT_PER_CLIENT);
      const hiddenDestinations = destinations.length - visibleDestinations.length;

      const visibleServices = services.slice(0, SERVICE_LIMIT_PER_CLIENT);
      const hiddenServices = services.length - visibleServices.length;

      const clientTitle = client.name && client.name !== client.ip
        ? client.name
        : client.ip;

      const clientSub = client.name && client.name !== client.ip
        ? client.ip
        : "";

      return `
              <tr>
                <td class="topdest-rank">${index + 1}</td>

                <td>
                  <div class="client-name">${esc(clientTitle)}</div>
                  ${clientSub ? `<div class="client-ip">${esc(clientSub)}</div>` : ""}
                </td>

                <td>
                  <div class="dest-compact">
                    <span class="dest-total">${destinations.length} destinos</span>
                    <span class="dest-conn">${client.connections} conexões</span>
                  </div>

                  <div class="dest-mini-list">
                    ${visibleDestinations.map(d => `
                      <span
                        class="dest-mini"
                        title="${esc(d.dstIp)}:${esc(d.dstPort)}/${esc(String(d.protocol).toUpperCase())}"
                      >
                        ${esc(d.dstIp)}
                      </span>
                    `).join("")}

                    ${hiddenDestinations > 0
          ? `<span class="dest-mini-more">+${hiddenDestinations}</span>`
          : ""
        }
                  </div>
                </td>

                <td>
                  <div class="svc-list">
                    ${visibleServices.map(s => `
                      <span class="svc-badge ${esc(s.className)}">
                        ${esc(s.name)} · ${s.count}
                      </span>
                    `).join("")}

                    ${hiddenServices > 0
          ? `<span class="svc-badge svc-more">+${hiddenServices}</span>`
          : ""
        }
                  </div>
                </td>

                <td>
                  <span class="conn-badge">${client.connections}</span>
                </td>
              </tr>
            `;
    }).join("")}
        </tbody>
      </table>
    `;
  }
}

