options.helpers:
function findContainer() {
  return (
    context?.element?.querySelector?.("#disk-table-container") ||
    document.getElementById("disk-table-container")
  );
}

function getLastValue(field) {
  const values = field.values;
  const len = values.length ?? 0;

  for (let i = len - 1; i >= 0; i--) {
    const v = values.get ? values.get(i) : values[i];
    if (v !== null && v !== undefined) return v;
  }

  return null;
}

function formatBytes(bytes) {
  const value = Number(bytes || 0);

  if (value >= 1024 ** 4) {
    return `${(value / 1024 / 1024 / 1024 / 1024).toFixed(2)} TB`;
  }

  if (value >= 1024 ** 3) {
    return `${(value / 1024 / 1024 / 1024).toFixed(1)} GB`;
  }

  if (value >= 1024 ** 2) {
    return `${(value / 1024 / 1024).toFixed(1)} MB`;
  }

  return `${value.toFixed(0)} B`;
}

function getDiskName(metric) {
  const text = String(metric || "");

  let match = text.match(/(Disk-[^:]+)\s*:/i);
  if (match) return match[1];

  match = text.match(/\((.*?)\)/);
  if (match) return match[1];

  match = text.match(/([A-Z]:)/i);
  if (match) return match[1];

  return "Disco";
}

function renderDiskSummary(rows) {
  const summaryEl =
    context?.element?.querySelector?.("#disk-summary-badges") ||
    document.getElementById("disk-summary-badges");

  if (!summaryEl) return;

  const totalCrit = rows.filter(r => r.status === "Crítico").length;
  const totalWarn = rows.filter(r => r.status === "Atenção").length;
  const totalOk = rows.filter(r => r.status === "OK").length;

  summaryEl.innerHTML = `
    <div class="disk-summary-item disk-summary-crit">
      <span class="disk-summary-dot"></span>
      <span class="disk-summary-label">Críticos</span>
      <span class="disk-summary-value">${totalCrit}</span>
    </div>

    <div class="disk-summary-item disk-summary-warn">
      <span class="disk-summary-dot"></span>
      <span class="disk-summary-label">Atenção</span>
      <span class="disk-summary-value">${totalWarn}</span>
    </div>

    <div class="disk-summary-item disk-summary-ok">
      <span class="disk-summary-dot"></span>
      <span class="disk-summary-label">OK</span>
      <span class="disk-summary-value">${totalOk}</span>
    </div>
  `;
}

function addMetric(disks, metricName, value) {
  const metric = String(metricName || "");
  const metricLower = metric.toLowerCase();
  const diskName = getDiskName(metric);

  if (!disks[diskName]) {
    disks[diskName] = {
      name: diskName,
      total: 0,
      used: 0,
      free: null,
      util: null
    };
  }

  if (metricLower.includes("total space")) {
    disks[diskName].total = Number(value || 0);
  }

  if (metricLower.includes("used space")) {
    disks[diskName].used = Number(value || 0);
  }

  if (
    metricLower.includes("available space") ||
    metricLower.includes("free space")
  ) {
    disks[diskName].free = Number(value || 0);
  }

  if (
    metricLower.includes("space utilization") ||
    metricLower.includes("space util")
  ) {
    disks[diskName].util = Number(value || 0);
  }
}

function collectDisksFromSeries() {
  const series = context?.panelData?.series || [];
  const disks = {};

  for (const frame of series) {
    const frameName = String(frame.name || "");
    const fields = frame.fields || [];

    const fieldNames =
      fields.find(f => f.name === "Field") ||
      fields.find(f => /field|name/i.test(f.name));

    const fieldValues =
      fields.find(f => f.name === "Last *") ||
      fields.find(f => f.name === "Last") ||
      fields.find(f => f.name === "Value") ||
      fields.find(f => /last|value/i.test(f.name));

    if (fieldNames && fieldValues) {
      const names = Array.from(fieldNames.values);
      const values = Array.from(fieldValues.values);

      for (let i = 0; i < names.length; i++) {
        addMetric(disks, names[i], values[i]);
      }

      continue;
    }

    for (const field of fields) {
      if (String(field.type).toLowerCase() === "time") continue;

      const displayName = String(field.config?.displayName || "");
      const fieldName = String(field.name || "");

      const metricName = `${frameName} ${displayName} ${fieldName}`.trim();
      const value = getLastValue(field);

      if (value !== null && value !== undefined) {
        addMetric(disks, metricName, value);
      }
    }
  }

  return disks;
}

function buildTable(container) {
  const disks = collectDisksFromSeries();

  const rows = Object.values(disks)
    .filter(d => d.total > 0 || d.used > 0 || d.free !== null)
    .map(disk => {
      const free = disk.free !== null ? disk.free : Math.max(disk.total - disk.used, 0);
      const pused = disk.util !== null
        ? disk.util
        : disk.total > 0
          ? (disk.used / disk.total) * 100
          : 0;

      let status = "OK";
      let statusClass = "status-ok";
      let progressClass = "progress-ok";
      let rowClass = "row-ok";

      if (pused >= 85) {
        status = "Crítico";
        statusClass = "status-crit";
        progressClass = "progress-crit";
        rowClass = "row-crit";
      } else if (pused >= 75) {
        status = "Atenção";
        statusClass = "status-warn";
        progressClass = "progress-warn";
        rowClass = "row-warn";
      }

      return {
        ...disk,
        free,
        pused,
        status,
        statusClass,
        progressClass,
        rowClass
      };
    })
    .sort((a, b) => b.pused - a.pused);

  if (!rows.length) {
    container.innerHTML = `<div class="empty-state">Nenhum disco encontrado.</div>`;
    return;
  }

  renderDiskSummary(rows);

  container.innerHTML = `
    <table class="disk-table">
      <thead>
        <tr>
          <th>Disco</th>
          <th style="text-align:right;">Total</th>
          <th style="text-align:right;">Usado</th>
          <th style="text-align:right;">Livre</th>
          <th>% Usado</th>
          <th style="text-align:center;">Status</th>
        </tr>
      </thead>
      <tbody>
        ${rows.map(d => `
          <tr class="${d.rowClass}">
            <td class="disk-name">${d.name}</td>
            <td style="text-align:right;">${formatBytes(d.total)}</td>
            <td style="text-align:right;">${formatBytes(d.used)}</td>
            <td style="text-align:right;">${formatBytes(d.free)}</td>
            <td class="progress-cell">
              <div class="progress-wrap">
                <div class="progress-bar ${d.progressClass}" style="width:${Math.min(d.pused, 100)}%"></div>
                <div class="progress-label">${d.pused.toFixed(1)}%</div>
              </div>
            </td>
            <td style="text-align:center;">
              <span class="status-badge ${d.statusClass}">${d.status}</span>
            </td>
          </tr>
        `).join("")}
      </tbody>
    </table>
  `;
}

(function waitRender(attempt = 0) {
  const container = findContainer();

  if (!container) {
    if (attempt < 20) {
      setTimeout(() => waitRender(attempt + 1), 100);
    }
    return;
  }

  buildTable(container);
})();

options.styles:
.disk-wrapper {
  padding: 12px;
  background: transparent;
  border-radius: 14px;
  color: #e8eefc;
  font-family: Arial, sans-serif;
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
  position: relative;
}

.disk-header-card {
  position: relative;
  display: flex;
  align-items: center;
  background: #1E223C;
  color: white;
  border-radius: 20px;
  padding: 20px 20px;
  margin-bottom: 14px;
  box-shadow: 0px 4px 6px rgba(0, 0, 0, 0.3);
  width: 100%;
  max-width: 100%;
  box-sizing: border-box;
}

.disk-header-left {
  display: flex;
  align-items: center;
  width: 100%;
}

.disk-header-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  width: 100%;
  flex-wrap: wrap;
}

.disk-header-icon {
  width: 45px;
  height: 45px;
  margin-left: 10px;
  margin-right: 15px;
  object-fit: contain;
  display: block;
  filter: invert(1) brightness(2);
  flex-shrink: 0;
}

.disk-header-texts {
  display: flex;
  flex-direction: column;
}

.title {
  flex-grow: 1;
  font-size: 16px;
  font-weight: bold;
  margin: 0;
  color: #ffffff;
}

.subtitle {
  font-size: 12px;
  color: #a9b4d0;
  margin: 0;
}

.disk-summary-badges {
  display: flex;
  align-items: center;
  gap: 10px;
  flex-wrap: wrap;
  justify-content: flex-end;
  margin-left: auto;
}

.disk-summary-item {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 12px;
  border-radius: 999px;
  font-size: 12px;
  font-weight: 700;
  line-height: 1;
  white-space: nowrap;
  border: 1px solid rgba(255, 255, 255, 0.08);
}

.disk-summary-label {
  opacity: 0.95;
}

.disk-summary-value {
  font-weight: 800;
}

.disk-summary-ok {
  background: #2ecc71;
  color: black;
  box-shadow: 0 0 10px rgba(46, 204, 113, 0.35);
}

.disk-summary-warn {
  background: #f1c40f;
  color: black;
  box-shadow: 0 0 10px rgba(241, 196, 15, 0.35);
}

.disk-summary-crit {
  background: #ff5f57;
  color: black;
  box-shadow: 0 0 10px rgba(255, 95, 87, 0.35);
}

.disk-summary-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: currentColor;
  opacity: 0.9;
}

/* container com scroll horizontal no mobile */
#disk-table-container {
  width: 100%;
  max-width: 100%;
  overflow-x: auto;
  overflow-y: visible;
  -webkit-overflow-scrolling: touch;
  border-radius: 20px;
  touch-action: pan-x pan-y;
  overscroll-behavior-x: contain;
  overscroll-behavior-y: auto;
}

#disk-table-container::-webkit-scrollbar {
  height: 8px;
}

#disk-table-container::-webkit-scrollbar-track {
  background: rgba(255, 255, 255, 0.06);
  border-radius: 999px;
}

#disk-table-container::-webkit-scrollbar-thumb {
  background: rgba(143, 162, 216, 0.45);
  border-radius: 999px;
}

.disk-table {
  width: 100%;
  min-width: 920px;
  max-width: none;
  border-collapse: separate;
  border-spacing: 0;
  overflow: hidden;
  border-radius: 20px;
  background: #1E223C;
  box-shadow: 0px 4px 6px rgba(0, 0, 0, 0.3);
}

.disk-table thead tr {
  background: #1E223C;
}

.disk-table th {
  text-align: left;
  font-size: 12px;
  color: #c8d1ea;
  font-weight: 700;
  padding: 12px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  text-transform: uppercase;
  letter-spacing: 0.4px;
  white-space: nowrap;
}

.disk-table td {
  padding: 12px 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
  font-size: 13px;
  color: #e8eefc;
  background: #1E223C;
  transition: background 0.35s ease;
  white-space: nowrap;
}

.disk-table td:first-child {
  white-space: normal;
}

.disk-table tbody tr:last-child td {
  border-bottom: none;
}

.disk-table tbody tr:hover td {
  background: #252A49;
}

.disk-table thead tr th:first-child {
  border-top-left-radius: 20px;
}

.disk-table thead tr th:last-child {
  border-top-right-radius: 20px;
}

.disk-table tbody tr:last-child td:first-child {
  border-bottom-left-radius: 20px;
}

.disk-table tbody tr:last-child td:last-child {
  border-bottom-right-radius: 20px;
}

.disk-name {
  font-weight: 700;
  color: #ffffff;
}

.status-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 78px;
  border-radius: 50px;
  padding: 6px 18px;
  color: black;
  font-size: 12px;
  font-weight: 800;
  text-align: center;
  border: none;
  box-shadow: none;
  white-space: nowrap;
}

.status-ok {
  background: #2ecc71;
  color: black;
}

.status-warn {
  background: #f1c40f;
  color: black;
}

.status-crit {
  background: #ff5f57;
  color: black;
}

.progress-cell {
  min-width: 220px;
}

.progress-wrap {
  position: relative;
  width: 100%;
  height: 18px;
  background: rgba(255, 255, 255, 0.08);
  border-radius: 999px;
  overflow: hidden;
}

.progress-bar {
  position: relative;
  height: 100%;
  border-radius: 999px;
  transition: width 0.5s ease;
  overflow: hidden;
}

.progress-bar::after {
  content: "";
  position: absolute;
  top: 0;
  left: -40%;
  width: 40%;
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(
    90deg,
    rgba(255, 255, 255, 0) 0%,
    rgba(255, 255, 255, 0.28) 50%,
    rgba(255, 255, 255, 0) 100%
  );
  pointer-events: none;
}

.progress-ok {
  background: linear-gradient(90deg, #2ecc71, #57e389);
}

.progress-warn {
  background: linear-gradient(90deg, #f1c40f, #f4d03f);
  box-shadow: 0 0 12px rgba(244, 208, 63, 0.18);
}

.progress-warn::after {
  animation: progressShine 2.4s infinite linear;
}

.progress-crit {
  background: linear-gradient(90deg, #e74c3c, #ff6b6b);
  box-shadow: 0 0 14px rgba(255, 107, 107, 0.22);
}

.progress-crit::after {
  animation: progressShine 1.4s infinite linear;
}

.progress-label {
  position: absolute;
  top: 50%;
  right: 8px;
  transform: translateY(-50%);
  font-size: 11px;
  font-weight: 700;
  color: #e8eefc;
  text-shadow: 0 1px 2px rgba(0, 0, 0, 0.45);
  z-index: 2;
  white-space: nowrap;
}

.disk-table tbody tr.row-ok td {
  background: #1E223C;
}

.disk-table tbody tr.row-warn td {
  background: rgba(241, 196, 15, 0.08);
  animation: rowWarnPulse 3s infinite ease-in-out;
}

.disk-table tbody tr.row-crit td {
  background: rgba(255, 95, 87, 0.10);
  animation: rowCritPulse 2s infinite ease-in-out;
}

.disk-table tbody tr.row-warn:hover td {
  background: rgba(241, 196, 15, 0.14);
}

.disk-table tbody tr.row-crit:hover td {
  background: rgba(255, 95, 87, 0.16);
}

.empty-state {
  padding: 16px;
  color: #a9b4d0;
  font-size: 13px;
}

@keyframes progressShine {
  0% {
    left: -40%;
  }
  100% {
    left: 110%;
  }
}

@keyframes rowWarnPulse {
  0%, 100% {
    background: rgba(241, 196, 15, 0.08);
  }
  50% {
    background: rgba(241, 196, 15, 0.14);
  }
}

@keyframes rowCritPulse {
  0%, 100% {
    background: rgba(255, 95, 87, 0.10);
  }
  50% {
    background: rgba(255, 95, 87, 0.18);
  }
}

@media (max-width: 1100px) {
  .disk-header-card {
    padding: 16px 16px;
  }

  .disk-header-top {
    align-items: flex-start;
    flex-direction: column;
  }

  .disk-summary-badges {
    width: 100%;
    justify-content: flex-start;
    margin-left: 0;
  }
}

@media (max-width: 768px) {
  .disk-wrapper {
    padding: 8px;
  }

  .disk-header-card {
    padding: 14px 14px;
    border-radius: 16px;
    margin-bottom: 10px;
  }

  .disk-header-icon {
    width: 38px;
    height: 38px;
    margin-left: 6px;
    margin-right: 12px;
  }

  .title {
    font-size: 15px;
  }

  .subtitle {
    font-size: 11px;
  }

  .disk-summary-badges {
    gap: 8px;
  }

  .disk-summary-item {
    padding: 7px 10px;
    font-size: 11px;
  }

  #disk-table-container {
    border-radius: 16px;
  }

  .disk-table {
    min-width: 820px;
    border-radius: 16px;
  }

  .disk-table th,
  .disk-table td {
    padding: 10px 10px;
    font-size: 12px;
  }

  .progress-cell {
    min-width: 180px;
  }

  .status-badge {
    font-size: 11px;
    padding: 5px 14px;
    min-width: 70px;
  }

  .progress-label {
    font-size: 10px;
  }
}

@media (max-width: 480px) {
  .disk-header-card {
    padding: 12px;
  }

  .disk-summary-item {
    font-size: 10px;
    padding: 6px 8px;
  }

  .disk-table {
    min-width: 760px;
  }

  .disk-table th,
  .disk-table td {
    padding: 8px 8px;
    font-size: 11px;
  }

  .progress-cell {
    min-width: 160px;
  }

  .disk-header-icon {
    width: 34px;
    height: 34px;
    margin-right: 10px;
  }
}
